SELECT u.id AS id, sp.student_no AS studentNo, u.real_name AS name, u.username AS username, sp.grade AS grade, sp.class_name AS className, sp.guardian AS guardian, '2026-03-05 13:45:29' AS syncedAt, sp.poverty_level AS povertyLevel, sp.is_sponsored AS isSponsored, sp.household_type AS householdType, sp.is_left_behind AS isLeftBehind, sp.is_disabled AS isDisabled, sp.is_single_parent AS isSingleParent, sp.is_key_concern AS isKeyConcern, sp.can_view AS canView, sp.can_edit AS canEdit FROM users u INNER JOIN student_profiles sp ON sp.student_id = u.id WHERE u.role = 'student' AND u.status <> 'inactive'
AND ( sp.student_no LIKE CONCAT('%', #{query.keyword}, '%') OR u.real_name LIKE CONCAT('%', #{query.keyword}, '%') OR u.username LIKE CONCAT('%', #{query.keyword}, '%') OR IFNULL(sp.guardian, '') LIKE CONCAT('%', #{query.keyword}, '%') OR IFNULL(sp.poverty_level, '') LIKE CONCAT('%', #{query.keyword}, '%') )
AND sp.grade = #{query.grade}
AND sp.class_name = #{query.className}
AND sp.is_sponsored = 1
AND sp.poverty_level = #{query.archiveFilter}
AND sp.can_view = #{query.canView}
AND sp.can_edit = #{query.canEdit}
ORDER BY u.created_at DESC

SELECT u.id FROM users u INNER JOIN student_profiles sp ON sp.student_id = u.id WHERE u.role = 'student' AND u.status <> 'inactive'
AND u.id IN
#{id}
